// Mark incoming companies as new and prepare for dedup
const companies = $('Execute Workflow Trigger').all();
return companies.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const source = company.source || company['VC Firm'] || 'Unknown';

  return { 
    json: { 
      ...company, 
      _isNewCompany: true,
      // Prepare dedup check data
      _dedupInput: {
        company: name,
        title: '',
        source: source,
        recordType: 'company'
      }
    } 
  };
});

// Log skipped duplicates for monitoring
const items = $input.all();
return items.map(item => {
  const dedupResult = item.json;
  return {
    json: {
      _skipped: true,
      _skipReason: 'cross_source_duplicate',
      _existingRecordId: dedupResult.existingRecordId,
      _allSources: dedupResult.allSources,
      _key: dedupResult.key,
      company_name: dedupResult._originalInput?.company,
      source: dedupResult._originalInput?.source
    }
  };
});

// Restore original company data for non-duplicates
const items = $input.all();
let markNewItems = [];
try { markNewItems = $('Mark as New & Prep Dedup').all(); } catch(e) { markNewItems = []; }

return items.map((item, index) => {
  const dedupResult = item.json;
  // Find matching original item by company name
  const companyName = dedupResult._originalInput?.company || '';
  const original = markNewItems.find(m => 
    (m.json.company_name || m.json['Company Name'] || '') === companyName
  );

  if (original) {
    return {
      json: {
        ...original.json,
        _dedupKey: dedupResult.key
      }
    };
  }

  // Fallback if no match
  return {
    json: {
      company_name: companyName,
      source: dedupResult._originalInput?.source,
      _dedupKey: dedupResult.key,
      _isNewCompany: true
    }
  };
});

const allItems = $input.all();
const newCompanies = [];
const existingRecords = [];

for (const item of allItems) {
  if (item.json._isNewCompany) {
    newCompanies.push(item);
  } else if (item.json.fields && item.json.fields['Company Name']) {
    existingRecords.push(item);
  } else if (item.json.id && item.json['Company Name']) {
    existingRecords.push({ json: { id: item.json.id, fields: item.json } });
  }
}

const normalize = (str) => str ? String(str).toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

const existingMap = new Map();
for (const item of existingRecords) {
  const fields = item.json.fields || item.json;
  const name = fields['Company Name'] || '';
  const url = fields['Company URL'] || '';
  const recordId = item.json.id;
  if (name) {
    existingMap.set(normalize(name), { id: recordId, hasUrl: !!url && url.length > 0 });
  }
}

const uniqueCompanies = [];
const addedNames = new Set();

for (const company of newCompanies) {
  const name = company.json.company_name || company.json['Company Name'];
  const newUrl = company.json.company_url || company.json['Company URL'] || '';
  if (!name) continue;

  const normalizedName = normalize(name);
  if (!normalizedName || addedNames.has(normalizedName)) continue;

  const existing = existingMap.get(normalizedName);

  if (existing) {
    if (!existing.hasUrl && newUrl) {
      addedNames.add(normalizedName);
      const cleanCompany = { ...company.json };
      delete cleanCompany._isNewCompany;
      cleanCompany._updateRecordId = existing.id;
      uniqueCompanies.push({ json: cleanCompany });
    }
    continue;
  }

  addedNames.add(normalizedName);
  const cleanCompany = { ...company.json };
  delete cleanCompany._isNewCompany;
  uniqueCompanies.push({ json: cleanCompany });
}

if (uniqueCompanies.length === 0) {
  return [{ json: { _empty: true, _message: 'No new companies found' } }];
}

return uniqueCompanies;

const items = $input.all();
return items.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const searchQuery = '"' + name + '" company funding employees series startup';
  return { json: { ...company, searchQuery } };
});

// v8.1: Fixed funding extraction - sanity cap at $5B, contextual matching, ignore PE fund sizes
const braveResponses = $input.all();
const companyDataItems = $('Build Search Query').all();

// Expanded PE/Growth Equity firm list (29 firms)
const peFirms = [
  'Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'TPG', 'Carlyle',
  'Bain Capital', 'Silver Lake', 'Francisco Partners', 'Accel-KKR',
  'LLR Partners', 'Warburg Pincus', 'Apollo', 'Insight Partners', 'GTCR',
  'Clearlake', 'Welsh Carson', 'Providence Equity', 'Leonard Green',
  'Hellman & Friedman', 'Advent', 'Golden Gate Capital', 'TA Associates',
  'Brighton Park Capital', 'General Atlantic', 'Summit Partners', 'SoftBank Vision Fund',
  'EQT Partners', 'Permira'
];

// Helper: Parse funding amount string to numeric value
const parseFundingAmount = (amountStr, unitStr) => {
  const amount = parseFloat(amountStr);
  const unit = unitStr.toLowerCase();
  if (unit === 'billion' || unit === 'b') return amount * 1000000000;
  if (unit === 'million' || unit === 'm') return amount * 1000000;
  if (unit === 'k' || unit === 'thousand') return amount * 1000;
  return amount;
};

// Helper: Format funding for display
const formatFunding = (numeric) => {
  if (numeric >= 1000000000) return `$${(numeric / 1000000000).toFixed(1)}B`;
  if (numeric >= 1000000) return `$${(numeric / 1000000).toFixed(1)}M`;
  if (numeric >= 1000) return `$${(numeric / 1000).toFixed(0)}K`;
  return `$${numeric}`;
};

const currentYear = new Date().getFullYear();
const MAX_BELIEVABLE_FUNDING = 5000000000; // $5B cap - no startup has raised more

return braveResponses.map((item, index) => {
  const braveResponse = item.json;
  const companyData = companyDataItems[index]?.json || {};
  const companyName = companyData.company_name || companyData['Company Name'] || '';
  const searchResults = braveResponse?.web?.results || [];
  const allText = searchResults.map(r => `${r.title || ''} ${r.description || ''}`).join(' ');

  // Extract employee count
  let employeeCount = null;
  const empMatch = allText.match(/([\d,]+)\s*(?:to\s*[\d,]+)?\s*employees?/i);
  if (empMatch) employeeCount = parseInt(empMatch[1].replace(/,/g, ''));

  // Extract funding stage
  let fundingStage = null;
  const stagePatterns = {
    'Series D': /Series\s*D/i,
    'Series C': /Series\s*C/i,
    'Series B': /Series\s*B/i,
    'Series A': /Series\s*A/i,
    'Seed': /\bSeed\b/i
  };
  for (const [stage, pattern] of Object.entries(stagePatterns)) {
    if (pattern.test(allText)) { fundingStage = stage; break; }
  }

  // v8.1: IMPROVED funding extraction with sanity checks
  // Priority 1: Contextual patterns (raised, funding, secured)
  // Priority 2: Any dollar amount with M/B suffix
  // Filter: Ignore amounts > $5B (PE fund sizes, not company funding)
  let totalFunding = null, totalFundingRaw = null;
  const fundingCandidates = [];

  // Priority patterns - these are more likely to be actual company funding
  const contextualPatterns = [
    /(?:raised|secur(?:ed|es)|total funding of|funding of|announced)\s*\$([\d.]+)\s*(million|billion|M|B)/gi,
    /\$([\d.]+)\s*(million|billion|M|B)\s*(?:raised|funding|round|series)/gi,
    /series\s*[A-D]\s*(?:funding|round)?\s*(?:of)?\s*\$([\d.]+)\s*(million|billion|M|B)/gi
  ];

  for (const pattern of contextualPatterns) {
    let match;
    while ((match = pattern.exec(allText)) !== null) {
      const numeric = parseFundingAmount(match[1], match[2]);
      if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) { // Min $100K, Max $5B
        fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 1 });
      }
    }
  }

  // Fallback: Any dollar amount (lower priority)
  if (fundingCandidates.length === 0) {
    const fallbackPattern = /\$([\d.]+)\s*(million|billion|M|B)/gi;
    let match;
    while ((match = fallbackPattern.exec(allText)) !== null) {
      const numeric = parseFundingAmount(match[1], match[2]);
      if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
        fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 2 });
      }
    }
  }

  // Select best candidate: prefer contextual matches, then largest reasonable amount
  if (fundingCandidates.length > 0) {
    // Sort by priority (1 first), then by amount (descending)
    fundingCandidates.sort((a, b) => {
      if (a.priority !== b.priority) return a.priority - b.priority;
      return b.numeric - a.numeric;
    });
    const best = fundingCandidates[0];
    totalFunding = best.numeric;
    totalFundingRaw = best.raw;
  }

  // Check for PE backing
  const isPEBacked = peFirms.some(f => new RegExp(f, 'i').test(allText));
  const peBackerFound = peFirms.find(f => new RegExp(f, 'i').test(allText)) || null;

  // Extract founded year
  let foundedYear = null;
  const foundMatch = allText.match(/(?:founded|established|since)\s*(?:in)?\s*(\d{4})/i);
  if (foundMatch) foundedYear = parseInt(foundMatch[1]);

  // Detect acquisition status
  let isAcquired = false;
  let acquiredBy = null;
  const acquirePatterns = [
    /acquired\s+by\s+([A-Z][a-zA-Z0-9\s]+)/i,
    /([A-Z][a-zA-Z0-9\s]+)\s+acquires?/i,
    /acquisition\s+by\s+([A-Z][a-zA-Z0-9\s]+)/i,
    /bought\s+by\s+([A-Z][a-zA-Z0-9\s]+)/i
  ];
  for (const pattern of acquirePatterns) {
    const match = allText.match(pattern);
    if (match) {
      isAcquired = true;
      acquiredBy = match[1]?.trim() || 'Unknown';
      break;
    }
  }
  if (!isAcquired && /\b(was acquired|has been acquired|acquired in \d{4})\b/i.test(allText)) {
    isAcquired = true;
  }

  // Detect if public company
  const isPublic = /\b(NYSE|NASDAQ|publicly traded|IPO|stock ticker|went public)\b/i.test(allText);

  // Detect if not B2B SaaS (biotech, hardware, crypto, consumer)
  const isBiotech = /\b(therapeutic|biologics|drug development|clinical trial|FDA approval|cell therapy|gene therapy)\b/i.test(allText);
  const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|IoT devices|chip|semiconductor)\b/i.test(allText) && !/\b(SaaS|software platform|cloud)\b/i.test(allText);
  const isCrypto = /\b(blockchain|cryptocurrency|web3|NFT|DeFi|token)\b/i.test(allText);
  const isConsumer = /\b(consumer app|DTC|direct-to-consumer|e-commerce|retail brand|vitamins|supplements|skincare)\b/i.test(allText);
  const isNotB2BSaaS = isBiotech || isHardware || isCrypto || isConsumer;

  // v8: Updated auto-disqualification logic with NEW thresholds
  // Gates: PE-backed, >$75M funding, >150 employees, acquired, public, not B2B SaaS, Series D+
  const autoDisqualifiers = [];
  if (isPEBacked) autoDisqualifiers.push(`PE-backed (${peBackerFound})`);
  if (employeeCount && employeeCount > 150) autoDisqualifiers.push(`>150 employees (${employeeCount})`);
  if (totalFunding && totalFunding > 75000000) autoDisqualifiers.push(`>$75M funding (${totalFundingRaw})`);
  if (isAcquired) autoDisqualifiers.push(`Acquired${acquiredBy ? ' by ' + acquiredBy : ''}`);
  if (isPublic) autoDisqualifiers.push('Public company');
  if (isNotB2BSaaS) {
    if (isBiotech) autoDisqualifiers.push('Biotech/pharma (not B2B SaaS)');
    else if (isHardware) autoDisqualifiers.push('Hardware company (not B2B SaaS)');
    else if (isCrypto) autoDisqualifiers.push('Crypto/Web3 (not B2B SaaS)');
    else if (isConsumer) autoDisqualifiers.push('Consumer/DTC (not B2B SaaS)');
  }
  if (['Series D'].includes(fundingStage)) autoDisqualifiers.push(`Late stage (${fundingStage})`);

  return {
    json: {
      company_name: companyData.company_name || companyData['Company Name'],
      company_url: companyData.company_url || companyData['Company URL'],
      description: companyData.description || companyData['Company Description'],
      source: companyData.source || companyData['VC Firm'] || 'Unknown',
      funding_stage: fundingStage,
      total_funding: totalFundingRaw,
      total_funding_numeric: totalFunding,
      employee_count: employeeCount,
      pe_backed: isPEBacked,
      pe_backer: peBackerFound,
      founded_year: foundedYear,
      is_acquired: isAcquired,
      acquired_by: acquiredBy,
      is_public: isPublic,
      is_biotech: isBiotech,
      is_hardware: isHardware,
      is_crypto: isCrypto,
      is_consumer: isConsumer,
      investors: peBackerFound || '',
      autoDisqualifiers,
      disqualify_reasons: autoDisqualifiers.join('; '),
      isAutoDisqualified: autoDisqualifiers.length > 0,
      _dedupKey: companyData._dedupKey,
      _updateRecordId: companyData._updateRecordId
    }
  };
});

// Prepare dedup registration for auto-disqualified record
const airtableRecord = $json;
let parseData = {};
try { parseData = $('Parse Enrichment').item?.json || {}; } catch(e) { parseData = {}; }

const normalize = (str) => str ? str.toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';
const company = parseData.company_name || '';
const key = `company:${normalize(company)}`;

return {
  json: {
    key: key,
    company: company,
    title: '',
    source: parseData.source || 'Unknown',
    recordType: 'company',
    airtableRecordId: airtableRecord.id
  }
};

const responses = $input.all();
const companyItems = $('Build Evaluation Prompt').all();

return responses.map((item, index) => {
  const response = item.json;
  const companyData = companyItems[index]?.json || {};

  let evaluation = {};
  try {
    const content = response.content?.[0]?.text || '';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
  } catch (e) {
    evaluation = { bucket: 'WATCH', total_score: 0, summary: 'Parse error - manual review needed' };
  }

  const statusMap = { 'APPLY': 'Apply', 'WATCH': 'Monitor', 'PASS': 'Skip' };
  const nextStepsMap = { 'APPLY': 'Apply Now', 'WATCH': 'Watch for Jobs', 'PASS': 'Skip' };

  return {
    json: {
      _updateRecordId: companyData._updateRecordId || null,
      _dedupKey: companyData._dedupKey,
      company_name: companyData.company_name,
      company_url: companyData.company_url,
      description: companyData.description,
      source: companyData.source,
      status: statusMap[evaluation.bucket] || 'Research',
      next_steps: nextStepsMap[evaluation.bucket] || 'Research More',
      total_score: evaluation.total_score || 0,
      sector_match: evaluation.sector_match || 'unknown',
      cs_hire_likelihood: evaluation.cs_hire_likelihood || '',
      product_type: evaluation.product_type || '',
      summary: evaluation.summary || '',
      funding_stage: companyData.funding_stage,
      total_funding: companyData.total_funding,
      employee_count: companyData.employee_count,
      pe_backed: companyData.pe_backed,
      founded_year: companyData.founded_year
    }
  };
});

// OPTIMIZED: Check job matches and LinkedIn connections using Map lookups
const evalItems = $('Parse Evaluation').all();
const jobListings = $('Search Job Listings').all();
const linkedInConnections = $('Search LinkedIn Connections').all();

const normalize = (str) => str ? String(str).toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

// Build a Map for O(1) job lookups
const jobsByCompany = new Map();
for (const job of jobListings) {
  const fields = job.json.fields || job.json;
  const company = normalize(fields['Company'] || fields['company'] || '');
  if (!company) continue;
  if (!jobsByCompany.has(company)) jobsByCompany.set(company, []);
  jobsByCompany.get(company).push(job);
}

// Build a Map for O(1) LinkedIn connection lookups
const connectionsByCompany = new Map();
for (const conn of linkedInConnections) {
  const fields = conn.json.fields || conn.json;
  // Use pre-computed normalized field if available, otherwise normalize
  const company = fields['Company Normalized'] || normalize(fields['Company'] || '');
  if (!company) continue;
  if (!connectionsByCompany.has(company)) connectionsByCompany.set(company, []);
  connectionsByCompany.get(company).push({
    name: fields['Name'] || '',
    position: fields['Position'] || '',
    linkedInUrl: fields['LinkedIn URL'] || ''
  });
}

const cxKeywords = ['customer', 'support', 'success', 'cx', 'experience', 'service', 'care', 'advocate', 'onboarding', 'implementation'];
const activeStatuses = ['new', 'reviewing', 'applied', 'interviewing', 'phone screen', 'on-site', 'offer'];

return evalItems.map(evalItem => {
  const companyName = evalItem.json.company_name || '';
  const normalizedCompany = normalize(companyName);

  // Check job matches
  const matchingJobs = jobsByCompany.get(normalizedCompany) || [];
  const activeJobs = matchingJobs.filter(job => {
    const fields = job.json.fields || job.json;
    const status = (fields['Review Status'] || '').toLowerCase();
    return activeStatuses.includes(status);
  });
  const cxJobs = activeJobs.filter(job => {
    const fields = job.json.fields || job.json;
    const title = (fields['Job Title'] || '').toLowerCase();
    return cxKeywords.some(kw => title.includes(kw));
  });

  // Check LinkedIn connections
  const matchingConnections = connectionsByCompany.get(normalizedCompany) || [];
  const hasNetworkConnection = matchingConnections.length > 0;
  const connectionNames = matchingConnections.map(c => `${c.name} (${c.position})`).join(', ');
  const connectionLinkedInUrl = matchingConnections.length > 0 ? matchingConnections[0].linkedInUrl : '';

  return {
    json: {
      ...evalItem.json,
      // Job matching fields
      hasActiveJobPosting: activeJobs.length > 0,
      hasCxJobPosting: cxJobs.length > 0,
      matchingJobCount: activeJobs.length,
      matchingCxJobCount: cxJobs.length,
      matchingJobTitles: activeJobs.map(j => (j.json.fields || j.json)['Job Title'] || '').filter(Boolean).join(', '),
      matchingJobIds: activeJobs.map(j => j.json.id).filter(Boolean),
      // LinkedIn connection fields
      hasNetworkConnection: hasNetworkConnection,
      connectionName: connectionNames,
      connectionLinkedInUrl: connectionLinkedInUrl,
      connectionCount: matchingConnections.length
    }
  };
});

